arguments.argument:
if global.gamePaused=false
{
  moveWave+=pi/50
  x+=cos(moveWave)/4
  
  if myProg=0
  {
    image_xscale+=0.01; image_yscale+=0.01
    if image_xscale=0.8
    {
      bCanDealDamage=1
      myProg=1
    }
  }
  else if myProg=1
  {
    scaleWave+=pi/60
    image_xscale=0.5+(sin(scaleWave+i)/8)
    image_yscale=0.5+(sin(scaleWave+i)/8)
  }
  enemyStepEvent()
}
